import { App, Plugin, PluginSettingTab, Setting, Platform, Notice } from 'obsidian';

type MicaMaterial = 'auto' | 'none' | 'mica' | 'acrylic' | 'tabbed';

interface PseudoMicaSettings {
    material: MicaMaterial;
    // Tint colors stored as hex; alpha stored separately 0-1
    lightTintColor: string;
    lightTintOpacity: number;
    darkTintColor: string;
    darkTintOpacity: number;
    // Extra blur applied via CSS backdrop-filter on top of native material
    extraBlur: number;
    // Follow Obsidian theme automatically
    followTheme: boolean;
}

const DEFAULT_SETTINGS: PseudoMicaSettings = {
    material: 'mica',
    lightTintColor: '#ffffff',
    lightTintOpacity: 0.35,
    darkTintColor: '#1e1e1e',
    darkTintOpacity: 0.45,
    extraBlur: 0,
    followTheme: true,
};

const OVERLAY_ID = 'pseudo-mica-overlay';

export default class PseudoMicaPlugin extends Plugin {
    settings: PseudoMicaSettings;
    electronWindow: any = null;
    private themeObserver: MutationObserver | null = null;

    async onload() {
        await this.loadSettings();

        if (!Platform.isWin) {
            console.warn('Pseudo Mica is Windows-only.');
            return;
        }

        this.electronWindow = this.getElectronWindow();
        if (!this.electronWindow) {
            new Notice('Pseudo Mica: Could not access Electron window.');
            return;
        }

        // Add settings tab
        this.addSettingTab(new PseudoMicaSettingTab(this.app, this));

        // Apply translucent classes & remove opaque backgrounds
        this.enableTranslucency();
        this.applyMaterial(this.settings.material);
        this.injectOverlay();
        this.updateOverlayStyle();
        this.preserveDragRegions();

        // Watch for theme changes so dark/light tints react automatically
        this.observeThemeChanges();

        // Command to cycle materials quickly
        this.addCommand({
            id: 'cycle-mica-material',
            name: 'Cycle background material',
            callback: () => this.cycleMaterial(),
        });

        this.addCommand({
            id: 'open-pseudo-mica-settings',
            name: 'Open Pseudo Mica settings',
            callback: () => {
                // @ts-ignore - setting is available at runtime
                this.app.setting.open();
                // @ts-ignore
                this.app.setting.openTabById(this.manifest.id);
            },
        });

        // Ribbon
        this.addRibbonIcon('layers', 'Pseudo Mica: cycle material', () => this.cycleMaterial());
    }

    onunload() {
        if (!Platform.isWin) return;

        try {
            this.electronWindow?.setBackgroundMaterial?.('none');
        } catch (e) {
            // ignore
        }

        document.body.classList.remove('is-translucent');
        document.body.classList.remove('pseudo-mica-enabled');
        document.body.removeAttribute('data-pseudo-mica-material');
        document.body.style.removeProperty('--workspace-background-translucent');
        document.body.style.removeProperty('--titlebar-background');
        document.body.style.removeProperty('--titlebar-background-focused');
        document.body.style.removeProperty('--pm-tint-color');
        document.body.style.removeProperty('--pm-extra-blur');

        document.getElementById(OVERLAY_ID)?.remove();

        this.themeObserver?.disconnect();
        this.themeObserver = null;
    }

    async loadSettings() {
        const raw = (await this.loadData()) ?? {};
        // Migrate older config that stored material as 'mica' string only or had 'vibrancy'
        const migrated: Partial<PseudoMicaSettings> = { ...raw };
        if (raw.vibrancy !== undefined) {
            delete (migrated as any).vibrancy;
        }
        this.settings = Object.assign({}, DEFAULT_SETTINGS, migrated);
    }

    async saveSettings() {
        await this.saveData(this.settings);
    }

    // ----- Material management -----

    applyMaterial(material: MicaMaterial) {
        if (!this.electronWindow?.setBackgroundMaterial) {
            new Notice('Pseudo Mica: setBackgroundMaterial unavailable on this Electron build.');
            return;
        }
        try {
            this.electronWindow.setBackgroundMaterial(material);
            document.body.setAttribute('data-pseudo-mica-material', material);
        } catch (e) {
            console.error('Pseudo Mica: failed to apply material', e);
            new Notice(`Pseudo Mica: failed to apply '${material}'.`);
        }
    }

    cycleMaterial() {
        const order: MicaMaterial[] = ['mica', 'acrylic', 'tabbed', 'none'];
        const idx = order.indexOf(this.settings.material);
        const next = order[(idx + 1) % order.length];
        this.settings.material = next;
        this.applyMaterial(next);
        this.updateOverlayStyle();
        this.saveSettings();
        new Notice(`Pseudo Mica: material = ${next}`);
    }

    // ----- Translucency setup -----

    private enableTranslucency() {
        document.body.classList.add('is-translucent');
        document.body.classList.add('pseudo-mica-enabled');
        document.body.style.setProperty('--workspace-background-translucent', 'transparent', 'important');
        document.body.style.setProperty('--titlebar-background', 'transparent', 'important');
        document.body.style.setProperty('--titlebar-background-focused', 'transparent', 'important');
    }

    // ----- Overlay (tint) -----

    private injectOverlay() {
        if (document.getElementById(OVERLAY_ID)) return;
        const overlay = document.createElement('div');
        overlay.id = OVERLAY_ID;
        overlay.classList.add('pseudo-mica-overlay');
        // Insert as first child so it sits behind everything else in stacking context
        document.body.prepend(overlay);
    }

    updateOverlayStyle() {
        const isDark = document.body.classList.contains('theme-dark');
        const color = isDark ? this.settings.darkTintColor : this.settings.lightTintColor;
        const alpha = isDark ? this.settings.darkTintOpacity : this.settings.lightTintOpacity;
        const rgba = hexToRgba(color, alpha);

        document.body.style.setProperty('--pm-tint-color', rgba);
        document.body.style.setProperty('--pm-extra-blur', `${this.settings.extraBlur}px`);
    }

    // ----- Drag region preservation -----

    // The translucent overlay must NEVER block the titlebar drag region.
    // We make the overlay pointer-events:none in CSS, but also ensure the
    // Obsidian titlebar keeps -webkit-app-region: drag so the window is movable.
    private preserveDragRegions() {
        const apply = () => {
            const titlebar = document.querySelector<HTMLElement>('.titlebar, .workspace-ribbon, .mod-windows .titlebar');
            // Obsidian's titlebar in frameless windows uses .titlebar
            const realTitlebar = document.querySelector<HTMLElement>('.titlebar');
            if (realTitlebar) {
                realTitlebar.style.setProperty('-webkit-app-region', 'drag');
                // Buttons inside the titlebar should remain interactive
                realTitlebar.querySelectorAll<HTMLElement>('button, .titlebar-button, .titlebar-button-container, input').forEach((el) => {
                    el.style.setProperty('-webkit-app-region', 'no-drag');
                });
            }
        };
        apply();
        // Re-apply when workspace layout changes
        this.app.workspace.onLayoutReady(apply);
        this.registerEvent(this.app.workspace.on('layout-change', apply));
    }

    // ----- Theme observer -----

    private observeThemeChanges() {
        if (!this.settings.followTheme) return;
        this.themeObserver?.disconnect();
        this.themeObserver = new MutationObserver(() => {
            this.updateOverlayStyle();
        });
        this.themeObserver.observe(document.body, { attributes: true, attributeFilter: ['class'] });
    }

    // ----- Electron -----

    private getElectronWindow(): any {
        try {
            // @ts-ignore
            const electron = window.electron ?? (window as any).require?.('electron');
            // @ts-ignore
            return electron?.remote?.getCurrentWindow?.()
                // @ts-ignore
                ?? electron?.getCurrentWindow?.()
                // @ts-ignore
                ?? require('@electron/remote')?.getCurrentWindow?.();
        } catch {
            return null;
        }
    }
}

// ----- Settings Tab -----

class PseudoMicaSettingTab extends PluginSettingTab {
    plugin: PseudoMicaPlugin;

    constructor(app: App, plugin: PseudoMicaPlugin) {
        super(app, plugin);
        this.plugin = plugin;
    }

    display(): void {
        const { containerEl } = this;
        containerEl.empty();

        containerEl.createEl('h2', { text: 'Pseudo Mica' });
        containerEl.createEl('p', {
            text: 'Apply Windows 11 background materials with a custom tint overlay. Window dragging is preserved via the titlebar.',
            cls: 'setting-item-description',
        });

        // ----- Material -----
        new Setting(containerEl)
            .setName('Background material')
            .setDesc('Mica: subtle, energy-efficient. Acrylic: heavier blur with stronger tint. Tabbed: like Mica with a tab variant.')
            .addDropdown((dd) =>
                dd
                    .addOption('mica', 'Mica')
                    .addOption('acrylic', 'Acrylic')
                    .addOption('tabbed', 'Tabbed')
                    .addOption('none', 'None (disable)')
                    .setValue(this.plugin.settings.material)
                    .onChange(async (value: MicaMaterial) => {
                        this.plugin.settings.material = value;
                        this.plugin.applyMaterial(value);
                        this.plugin.updateOverlayStyle();
                        await this.plugin.saveSettings();
                    })
            );

        // ----- Light tint color -----
        new Setting(containerEl)
            .setName('Light mode tint color')
            .setDesc('Color tint applied on top of the material when the theme is light.')
            .addColorPicker((cp) =>
                cp
                    .setValue(this.plugin.settings.lightTintColor)
                    .onChange(async (value) => {
                        this.plugin.settings.lightTintColor = value;
                        this.plugin.updateOverlayStyle();
                        await this.plugin.saveSettings();
                    })
            );

        new Setting(containerEl)
            .setName('Light mode tint opacity')
            .setDesc('Opacity of the light mode tint overlay (0 = fully transparent, 1 = fully opaque).')
            .addSlider((s) =>
                s
                    .setLimits(0, 1, 0.01)
                    .setValue(this.plugin.settings.lightTintOpacity)
                    .setDynamicTooltip()
                    .onChange(async (value) => {
                        this.plugin.settings.lightTintOpacity = value;
                        this.plugin.updateOverlayStyle();
                        await this.plugin.saveSettings();
                    })
            );

        // ----- Dark tint color -----
        new Setting(containerEl)
            .setName('Dark mode tint color')
            .setDesc('Color tint applied on top of the material when the theme is dark.')
            .addColorPicker((cp) =>
                cp
                    .setValue(this.plugin.settings.darkTintColor)
                    .onChange(async (value) => {
                        this.plugin.settings.darkTintColor = value;
                        this.plugin.updateOverlayStyle();
                        await this.plugin.saveSettings();
                    })
            );

        new Setting(containerEl)
            .setName('Dark mode tint opacity')
            .setDesc('Opacity of the dark mode tint overlay.')
            .addSlider((s) =>
                s
                    .setLimits(0, 1, 0.01)
                    .setValue(this.plugin.settings.darkTintOpacity)
                    .setDynamicTooltip()
                    .onChange(async (value) => {
                        this.plugin.settings.darkTintOpacity = value;
                        this.plugin.updateOverlayStyle();
                        await this.plugin.saveSettings();
                    })
            );

        // ----- Extra CSS blur -----
        new Setting(containerEl)
            .setName('Extra CSS blur')
            .setDesc('Additional CSS backdrop blur (in pixels) on top of the native material. Costs performance. Leave at 0 for pure native look.')
            .addSlider((s) =>
                s
                    .setLimits(0, 40, 1)
                    .setValue(this.plugin.settings.extraBlur)
                    .setDynamicTooltip()
                    .onChange(async (value) => {
                        this.plugin.settings.extraBlur = value;
                        this.plugin.updateOverlayStyle();
                        await this.plugin.saveSettings();
                    })
            );

        // ----- Reset -----
        new Setting(containerEl)
            .setName('Reset to defaults')
            .setDesc('Restore all settings to their defaults.')
            .addButton((b) =>
                b
                    .setButtonText('Reset')
                    .setWarning()
                    .onClick(async () => {
                        this.plugin.settings = Object.assign({}, DEFAULT_SETTINGS);
                        await this.plugin.saveSettings();
                        this.plugin.applyMaterial(this.plugin.settings.material);
                        this.plugin.updateOverlayStyle();
                        this.display();
                    })
            );
    }
}

// ----- Helpers -----

function hexToRgba(hex: string, alpha: number): string {
    const clean = hex.replace('#', '').trim();
    let r = 0, g = 0, b = 0;
    if (clean.length === 3) {
        r = parseInt(clean[0] + clean[0], 16);
        g = parseInt(clean[1] + clean[1], 16);
        b = parseInt(clean[2] + clean[2], 16);
    } else if (clean.length === 6) {
        r = parseInt(clean.substring(0, 2), 16);
        g = parseInt(clean.substring(2, 4), 16);
        b = parseInt(clean.substring(4, 6), 16);
    }
    const a = Math.max(0, Math.min(1, alpha));
    return `rgba(${r}, ${g}, ${b}, ${a})`;
}
